import{_ as a,o as s,c as n,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Safe cleanup across macOS, Windows, and Linux","description":"How Aerosol handles disk cleanup on macOS, Windows, and Linux — Trash, permanent delete, and why cross-platform tools still need platform-aware habits.","frontmatter":{"title":"Safe cleanup across macOS, Windows, and Linux","description":"How Aerosol handles disk cleanup on macOS, Windows, and Linux — Trash, permanent delete, and why cross-platform tools still need platform-aware habits.","date":"2026-04-03T00:00:00.000Z"},"headers":[],"relativePath":"blog/safe-cleanup-cross-platform.md","filePath":"blog/safe-cleanup-cross-platform.md","lastUpdated":1775592403000}'),t={name:"blog/safe-cleanup-cross-platform.md"};function r(i,e,l,d,c,p){return s(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="safe-cleanup-across-macos-windows-and-linux" tabindex="-1">Safe cleanup across macOS, Windows, and Linux <a class="header-anchor" href="#safe-cleanup-across-macos-windows-and-linux" aria-label="Permalink to &quot;Safe cleanup across macOS, Windows, and Linux&quot;">​</a></h1><p>Aerosol uses one codebase for <strong>macOS</strong>, <strong>Windows</strong>, and <strong>Linux</strong>, but each OS has different trash APIs, permissions, and “safe” defaults. Here’s how to think about cleanup without surprises.</p><h2 id="use-preview-first" tabindex="-1">Use preview first <a class="header-anchor" href="#use-preview-first" aria-label="Permalink to &quot;Use preview first&quot;">​</a></h2><p>Before any delete run, use <strong>preview</strong> (dry run) and scan the list. Large scans are paginated so you’re not scrolling thousands of rows blindly. If something looks unfamiliar, leave it unchecked.</p><h2 id="trash-vs-permanent-delete" tabindex="-1">Trash vs permanent delete <a class="header-anchor" href="#trash-vs-permanent-delete" aria-label="Permalink to &quot;Trash vs permanent delete&quot;">​</a></h2><p>Where the platform supports it, Aerosol can <strong>move items to Trash</strong> instead of deleting immediately. That’s the closest thing to an undo for bulk cleanup. Permanent delete is faster and irreversible — use it only when you’re sure.</p><h2 id="macos-gatekeeper-and-downloads" tabindex="-1">macOS Gatekeeper and downloads <a class="header-anchor" href="#macos-gatekeeper-and-downloads" aria-label="Permalink to &quot;macOS Gatekeeper and downloads&quot;">​</a></h2><p>Binaries from GitHub are <strong>not notarized</strong>. If macOS says the app is “damaged,” that’s usually <strong>Gatekeeper</strong>, not corruption. The <a href="/manual#macos-install-github-release-builds">user manual</a> covers <strong>Open Anyway</strong>, <code>xattr</code>, and right-click <strong>Open</strong>.</p><h2 id="linux-paths-and-permissions" tabindex="-1">Linux paths and permissions <a class="header-anchor" href="#linux-paths-and-permissions" aria-label="Permalink to &quot;Linux paths and permissions&quot;">​</a></h2><p>Some caches live under <code>~/.cache</code> or project dirs; others need elevated rights. Aerosol won’t silently escalate — work within your user’s home unless you deliberately run with broader permissions.</p><h2 id="windows-and-long-paths" tabindex="-1">Windows and long paths <a class="header-anchor" href="#windows-and-long-paths" aria-label="Permalink to &quot;Windows and long paths&quot;">​</a></h2><p>Very deep <code>node_modules</code> or old build trees can hit path limits on some setups. If a path fails, shorten the tree or exclude that root from the scan and clean in smaller chunks.</p><p>Consistency matters: <strong>preview → select → delete</strong> beats “clean everything” every time.</p>',13)])])}const m=a(t,[["render",r]]);export{u as __pageData,m as default};
